/**
 * Based on WorkOrder.tiprep value
 *
 * A: Avería
 * G: Garantía
 * M: Mantenimiento
 * P: Pre-montaje
 * C: Reconstrucción
 * J: Montaje
 * R: Reparación
 * T: Taller
 * I: Instalación
 * O: Otros
 */
export type WorkOrderTipRep = 'A' | 'G' | 'M' | 'P' | 'C' | 'J' | 'R' | 'T' | 'I' | 'O';

// TODO: use translation service
export const WorkOrderTipRepMap: { [K in WorkOrderTipRep]: string } = {
    A: 'Avería',
    G: 'Garantía',
    M: 'Mantenimiento',
    P: 'Pre-montaje',
    C: 'Reconstrucción',
    J: 'Montaje',
    R: 'Reparación',
    T: 'Taller',
    I: 'Instalación',
    O: 'Otros',
};

